async (params, browser) => {
  // Open user profile
  await browser.open(`https://www.tiktok.com/@${params.username}`)

  // Wait for profile to load
  await browser.waitForSelector('[data-e2e="user-subtitle"], [data-e2e="followers-count"]', 15000)

  // Let profile fully render
  await browser.wait(3000)

  // Scroll to load recent videos
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(2000)

  // Extract profile info and recent videos
  const profile_data = await browser.evaluate(`const displayNameEl = document.querySelector('[data-e2e="user-title"], h1[data-e2e="user-title"], .share-title'); const usernameEl = document.querySelector('[data-e2e="user-subtitle"], h2[data-e2e="user-subtitle"], .share-sub-title'); const bioEl = document.querySelector('[data-e2e="user-bio"], .share-desc'); const followingEl = document.querySelector('[data-e2e="following-count"], strong[title]'); const followersEl = document.querySelector('[data-e2e="followers-count"]'); const likesEl = document.querySelector('[data-e2e="likes-count"]'); const avatarEl = document.querySelector('[data-e2e="user-avatar"] img, .avatar img, img[class*="avatar"]'); const verifiedEl = document.querySelector('[data-e2e="verify-badge"], svg[class*="verified"]'); const videos = []; const videoItems = document.querySelectorAll('[data-e2e="user-post-item"], [data-e2e="user-post-item-list"] > div, .video-feed-item'); for (let i = 0; i < Math.min(videoItems.length, 12); i++) { const item = videoItems[i]; const linkEl = item.querySelector('a[href*="/video/"]'); const descEl = item.querySelector('[data-e2e="user-post-item-desc"] a, a[title]'); const viewsEl = item.querySelector('[data-e2e="video-views"], strong.video-count, .view-count'); const thumbEl = item.querySelector('img[src*="tiktokcdn"], img.poster, picture img'); videos.push({ description: descEl ? (descEl.getAttribute('title') || descEl.textContent.trim()).substring(0, 200) : '', views: viewsEl ? viewsEl.textContent.trim() : '', thumbnail: thumbEl ? thumbEl.src : '', url: linkEl ? linkEl.href : '' }); } return { display_name: displayNameEl ? displayNameEl.textContent.trim() : '', username: usernameEl ? usernameEl.textContent.trim() : '@' + params.username + '', bio: bioEl ? bioEl.textContent.trim().substring(0, 500) : '', following_count: followingEl ? followingEl.textContent.trim() : '', followers_count: followersEl ? followersEl.textContent.trim() : '', likes_count: likesEl ? likesEl.textContent.trim() : '', is_verified: !!verifiedEl, avatar: avatarEl ? avatarEl.src : '', video_count: videos.length, recent_videos: videos }`)

  return profile_data
}
